import{_ as t,o as s,c as n,ag as e}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"懒人教程：让 AI 帮你做整个世界","description":"","frontmatter":{},"headers":[],"relativePath":"creator-guide/02-tutorial-agent.md","filePath":"creator-guide/02-tutorial-agent.md","lastUpdated":null}'),l={name:"creator-guide/02-tutorial-agent.md"};function o(p,a,i,r,d,c){return s(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="懒人教程-让-ai-帮你做整个世界" tabindex="-1">懒人教程：让 AI 帮你做整个世界 <a class="header-anchor" href="#懒人教程-让-ai-帮你做整个世界" aria-label="Permalink to &quot;懒人教程：让 AI 帮你做整个世界&quot;">​</a></h1><blockquote><p>上一篇教程手把手教你填了每个字段。这篇教程告诉你——其实不用自己填，让 Yumina 的 AI 助手帮你搞定就行 (￣▽￣)ノ</p></blockquote><p>我们要做的还是同一个游戏：<strong>&quot;伪人&quot;</strong>——末日恐怖生存，判断敲门者是人是怪，活过14天。但这次，我们只靠 Studio 里的 AI Agent 来完成。</p><hr><h2 id="什么是-studio-ai-agent" tabindex="-1">什么是 Studio AI Agent <a class="header-anchor" href="#什么是-studio-ai-agent" aria-label="Permalink to &quot;什么是 Studio AI Agent&quot;">​</a></h2><p>Studio 里的 AI Assistant 不只是聊天——它是一个能<strong>直接修改你世界</strong>的 AI 助手。你用大白话说&quot;帮我加一个生命值变量&quot;，它就真的帮你创建好了。</p><p>它的工作方式：</p><ol><li>你描述需求</li><li>AI 分析后提出修改方案（会告诉你它要做什么）</li><li>你点 <strong>批准（Approve）</strong> → 修改生效</li><li>不满意就点 <strong>拒绝（Reject）</strong>，AI 会调整方案</li></ol><p>所有修改都有快照备份，随时可以回滚，不用怕搞坏 ∠( ᐛ 」∠)＿</p><hr><h2 id="第一步-创建世界-进入-studio" tabindex="-1">第一步：创建世界 + 进入 Studio <a class="header-anchor" href="#第一步-创建世界-进入-studio" aria-label="Permalink to &quot;第一步：创建世界 + 进入 Studio&quot;">​</a></h2><p>这一步还是要自己来：</p><ol><li>点左侧导航栏的 <strong>创建（Create）</strong> 按钮</li><li>选 <strong>空白项目（Blank Project）</strong></li><li>左上角填个名字：<code>伪人</code></li><li>点编辑器顶部的 <strong>进入 Studio（Enter Studio）</strong></li></ol><p>进入 Studio 后，你会看到左侧有 <strong>AI Assistant</strong> 面板。这就是你接下来的主要工作区。</p><hr><h2 id="第二步-告诉-ai-你想做什么" tabindex="-1">第二步：告诉 AI 你想做什么 <a class="header-anchor" href="#第二步-告诉-ai-你想做什么" aria-label="Permalink to &quot;第二步：告诉 AI 你想做什么&quot;">​</a></h2><p>在 AI Assistant 的输入框里，把你的游戏构想一口气告诉它。越详细越好——AI 拿到的信息越多，出来的东西越对。</p><p>复制下面这段发给它：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我做一个末日恐怖生存游戏，类似 &quot;No, I&#39;m not a Human&quot;。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>设定：末日降临，城市中出现了外表酷似人类的&quot;访客&quot;。玩家独自在家，每晚会有人来敲门。玩家需要判断来者是人是怪，决定是否开门。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>游戏规则：</span></span>
<span class="line"><span>- 游戏持续14天（14个夜晚）</span></span>
<span class="line"><span>- 夜晚：有2-3个敲门者，玩家通过猫眼观察、隔门对话来判断</span></span>
<span class="line"><span>- 白天：自由探索房间、使用物品</span></span>
<span class="line"><span>- 访客的特征：牙齿过于整齐、瞳孔不正常、皮肤纹理异样</span></span>
<span class="line"><span>- 人类有正常的不完美特征：龋齿、黑眼圈、伤疤</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我需要这些变量：</span></span>
<span class="line"><span>- player_hp（生命值，0-5，默认3）：被访客攻击 -1，让 Pale Stranger 进门直接归零</span></span>
<span class="line"><span>- energy_current（体力，0-8，默认3）：检查访客和射击消耗 1 点，猫眼观察和对话免费，白天恢复到上限</span></span>
<span class="line"><span>- game_day（天数，1-14）：每完成一个夜晚-白天周期 +1</span></span>
<span class="line"><span>- game_phase（阶段）：&quot;Night&quot; 或 &quot;Day&quot;</span></span>
<span class="line"><span>- player_has_gun（有枪，默认true）：射击消耗 1 点体力</span></span>
<span class="line"><span></span></span>
<span class="line"><span>帮我写好系统设定词条、开场白，还有关键词触发的世界书词条（敲门事件、猫眼观察、房间搜索）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>再帮我做一个 CRT 监控器风格的消息渲染器：</span></span>
<span class="line"><span>- 夜晚/白天相位标题（从 AI 回复中提取 &quot;🌑 **NIGHT X**&quot; 或 &quot;☀️ **DAY X**&quot;，做成 CRT 绿色发光 / 琥珀色标题，带扫描线效果）</span></span>
<span class="line"><span>- 敲门动画（从回复中提取 ***三星号文字***，做成红色抖动大字）</span></span>
<span class="line"><span>- 可点击选择按钮（提取 &quot;Suggested Choices:&quot; 后面的 A/B/C/D/E 选项，点击自动发送）</span></span>
<span class="line"><span>- 底部 HUD 状态栏（等宽字体，显示体力/HP/武装状态）</span></span>
<span class="line"><span>- 整体黑绿色末日风格</span></span></code></pre></div><hr><h2 id="第三步-审核-ai-的方案" tabindex="-1">第三步：审核 AI 的方案 <a class="header-anchor" href="#第三步-审核-ai-的方案" aria-label="Permalink to &quot;第三步：审核 AI 的方案&quot;">​</a></h2><p>AI 会开始工作。你会看到它一步步思考，然后提出修改方案。每次它要修改你的世界时，会弹出一张 <strong>审核卡片</strong>，列出它要做的操作。</p><p>比如：</p><ul><li><code>create_variable</code> — 创建 health 变量</li><li><code>create_entry</code> — 创建系统设定词条</li><li><code>write_message_renderer</code> — 写渲染器代码</li></ul><p>看一眼操作列表，觉得没问题就点 <strong>批准（Approve）</strong>。AI 会继续下一步。</p><div class="tip custom-block"><p class="custom-block-title">不用一次搞定</p><p>AI 可能需要好几轮审核才能完成所有内容。每轮它会做一批操作，你批准后它继续。整个过程可能有 3-5 轮审核——耐心点，让它做完 (•̀ᴗ•́)و</p></div><div class="tip custom-block"><p class="custom-block-title">不满意怎么办</p><p>如果你觉得某个操作不对（比如变量默认值设错了），点 <strong>拒绝（Reject）</strong>，然后告诉 AI 哪里要改：&quot;health 的默认值应该是 100 不是 50&quot;。它会调整方案重新提交。</p></div><hr><h2 id="第四步-检查和微调" tabindex="-1">第四步：检查和微调 <a class="header-anchor" href="#第四步-检查和微调" aria-label="Permalink to &quot;第四步：检查和微调&quot;">​</a></h2><p>AI 做完之后，退出 Studio 回到编辑器看看它帮你创建了什么。逐个检查：</p><ul><li><strong>词条（Lorebook）</strong> — 系统设定写得对不对？世界书词条够不够？</li><li><strong>变量（Variables）</strong> — 类型、默认值、行为规则是否合理？</li><li><strong>开场白（First Message）</strong> — 开场白氛围到位吗？</li><li><strong>消息渲染器（Message Renderer）</strong> — 预览效果满意吗？</li></ul><p>如果有需要调整的地方，你有两个选择：</p><ol><li><strong>回 Studio 继续聊</strong> — 告诉 AI &quot;把开场白改短一点&quot;、&quot;血条颜色换成暗红&quot;</li><li><strong>直接手动改</strong> — 在编辑器里自己改字段，就像上一篇教程教的那样</li></ol><p>别忘了去 <strong>概览（Overview）</strong> 把发布信息填好：封面图、描述、标签、语言。</p><hr><h2 id="第五步-测试和发布" tabindex="-1">第五步：测试和发布 <a class="header-anchor" href="#第五步-测试和发布" aria-label="Permalink to &quot;第五步：测试和发布&quot;">​</a></h2><p>点 <strong>保存（Save）</strong>，然后开个新会话测试。检查清单和手动教程一样：</p><table tabindex="0"><thead><tr><th>检查项</th><th>怎么验证</th></tr></thead><tbody><tr><td>开场白显示</td><td>进入后自动出现第一条消息</td></tr><tr><td>状态面板</td><td>消息上方有血条、体力条、天数</td></tr><tr><td>指令生效</td><td>互动后变量会跟着变</td></tr><tr><td>世界书触发</td><td>提到&quot;猫眼&quot;后 AI 按规则描述</td></tr></tbody></table><p>测试中发现问题？回 Studio 告诉 AI：&quot;测试的时候发现 AI 不扣血，帮我检查一下 health 变量的行为规则&quot;。AI 会帮你诊断和修复。</p><p>测试没问题了？回到 <strong>发现（Discover）</strong> 页面，点顶部的 <strong>发布（Publish）</strong> 按钮，选你的世界，设好年龄分级和可见性，发布！</p><hr><h2 id="跟-agent-聊天的技巧" tabindex="-1">跟 Agent 聊天的技巧 <a class="header-anchor" href="#跟-agent-聊天的技巧" aria-label="Permalink to &quot;跟 Agent 聊天的技巧&quot;">​</a></h2><h3 id="_1-第一条消息尽量详细" tabindex="-1">1. 第一条消息尽量详细 <a class="header-anchor" href="#_1-第一条消息尽量详细" aria-label="Permalink to &quot;1. 第一条消息尽量详细&quot;">​</a></h3><p>AI 拿到的上下文越多，越不需要反复修改。在第一条消息里尽量包含：</p><ul><li>游戏类型和核心玩法</li><li>需要哪些变量，每个变量的含义</li><li>风格和氛围描述</li><li>你想要什么样的 UI</li></ul><h3 id="_2-分步迭代比一步到位更靠谱" tabindex="-1">2. 分步迭代比一步到位更靠谱 <a class="header-anchor" href="#_2-分步迭代比一步到位更靠谱" aria-label="Permalink to &quot;2. 分步迭代比一步到位更靠谱&quot;">​</a></h3><p>如果你的世界很复杂，不要试图在一条消息里说完所有需求。可以分步来：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一轮：&quot;帮我做一个恐怖生存游戏，先把系统设定、变量和开场白搞定&quot;</span></span>
<span class="line"><span>→ 审核、批准</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二轮：&quot;现在帮我加世界书词条，需要敲门事件、猫眼观察、房间搜索这几个&quot;</span></span>
<span class="line"><span>→ 审核、批准</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三轮：&quot;最后帮我做一个暗色恐怖风格的消息渲染器，显示血条和天数&quot;</span></span>
<span class="line"><span>→ 审核、批准</span></span></code></pre></div><h3 id="_3-给反馈要具体" tabindex="-1">3. 给反馈要具体 <a class="header-anchor" href="#_3-给反馈要具体" aria-label="Permalink to &quot;3. 给反馈要具体&quot;">​</a></h3><p>❌ &quot;渲染器不好看&quot; — AI 不知道哪里不好看 ✅ &quot;渲染器的血条太细了，加粗一倍。背景颜色太亮，换成纯黑 #000&quot; — AI 知道该改什么</p><h3 id="_4-善用-canvas-预览" tabindex="-1">4. 善用 Canvas 预览 <a class="header-anchor" href="#_4-善用-canvas-预览" aria-label="Permalink to &quot;4. 善用 Canvas 预览&quot;">​</a></h3><p>Studio 右侧的 Canvas 面板可以实时预览渲染器效果。AI 修改完渲染器后，去 Canvas 看看效果，不满意就继续说。</p><hr><h2 id="手动-vs-agent-对比" tabindex="-1">手动 vs Agent 对比 <a class="header-anchor" href="#手动-vs-agent-对比" aria-label="Permalink to &quot;手动 vs Agent 对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>手动教程</th><th>Agent 教程</th></tr></thead><tbody><tr><td>耗时</td><td>30-60 分钟</td><td>5-15 分钟</td></tr><tr><td>学到什么</td><td>每个字段的含义和用法</td><td>如何跟 AI 高效协作</td></tr><tr><td>适合谁</td><td>想深入理解引擎的人</td><td>想快速出活的人</td></tr><tr><td>灵活度</td><td>完全控制每个细节</td><td>AI 帮你做大部分，你微调</td></tr><tr><td>建议</td><td>第一次做世界先走手动</td><td>熟悉之后用 Agent 提效</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">最佳实践</p><p>先跟着手动教程做一遍，理解引擎的核心概念。之后再用 Agent——你知道&quot;它在做什么&quot;才能给出好的指令，也更容易发现它做错的地方。</p></div><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>你已经掌握了两种做世界的方式。接下来：</p><ul><li>想深入了解某个功能？翻 <a href="./00-welcome.html#功能参考">功能参考</a> 部分</li><li>想看更复杂的世界怎么做？<strong>进阶教程</strong>（以&quot;壺中の毒 · 大逃杀&quot;为蓝本）即将推出</li><li>想让世界更好看？看 <a href="./07-components.html">自定义前端指南</a></li></ul><p>现在去做你自己的世界吧 ᕕ( ᐛ )ᕗ</p>`,61)])])}const g=t(l,[["render",o]]);export{h as __pageData,g as default};
